  ('generalpolice-410e2224-moex-00169', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '下列何者情形符合公務員服務法之規定？', '["甲於民國108年1月1日自金融監督管理委員會銀行局離職，於110年5月10日擔任商業銀 行之獨立董事", "乙機關首長許可其所屬之公務員丙至某大學兼課", "丁軍人於中秋節前，經長官派往農民家中協助收割農作物，收受該農民贈送之中秋節禮品", "戊公務員依法令兼任其他職務，並領取兼任職之薪資"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00170', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-111-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '依司法院大法官解釋意旨，關於公務人員保障制度之敘述，下列何者錯誤？', '["公務人員保障法中之申訴再申訴制度，限制公務人員之權利救濟，不符合憲法第16條之訴訟 權保障", "外勤消防人員之服勤務時數與超時服勤補償規定，立法者有義務另為必要合理之處理", "公務人員之健康權，為憲法所保障，旨在保障人民生理及心理機能之完整性，不受任意侵害", "管理措施是否違反公務人員之權利，應該考量其行政機關所採取措施之目的、性質以及干預之 程度，如屬顯然輕微之干預，即難謂構成權利之侵害"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:38+00:00", "source_pdf_sha1": "6f9daeb9f9b2", "answer_pdf_sha1": "9d557904b39a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
